import React, { useEffect, useState } from 'react';
import './App.css';
import Gun from 'gun';
import 'gun/sea';
import 'gun/axe';

function App() {

  const gun = Gun('https://gunrelayeurope.herokuapp.com/gun');
  const jeff = gun.get('jeff')

  const [first, setfirst] = useState(0)

  useEffect(() => {

    // window.addEventListener('storage', (event) => { window.location.reload() });

    gun.get('jeff').on((data) => { console.log(data); setfirst(data.age) })

  }, [gun])


  return (
    <div className="App">
      <p>{first}</p>
      <button onClick={() =>
        jeff.put({
          age: first+1,
          gender: 'male',
          happy: true
        })
      }>BB</button>
    </div>
  );
}

export default App;
